  FOR SELECT TO authenticated
  USING (
    (SELECT role FROM public.staff_profiles WHERE id = auth.uid()) IN
      ('branch_manager', 'supervision_staff', 'maintenance_staff')
  );

-- Staff: insert (branch_manager, supervision_staff, maintenance_staff)
