-- ============================================================================
-- Migration 007: Create maintenance-photos storage bucket
-- ============================================================================
-- Creates a private storage bucket for maintenance request photo uploads.
-- Bucket config: 5MB limit, JPEG/PNG/WebP only, private (signed URLs).
-- ============================================================================

-- 1. Create the bucket
INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)
VALUES (
  'maintenance-photos',
  'maintenance-photos',
  false,
  5242880,
  ARRAY['image/jpeg', 'image/png', 'image/webp']
)
ON CONFLICT (id) DO NOTHING;

-- 2. Allow authenticated users to read objects (needed for signed URL generation)
CREATE POLICY "Authenticated users can read maintenance photos"
ON storage.objects FOR SELECT TO authenticated
USING (bucket_id = 'maintenance-photos');

-- 3. Allow authenticated staff to upload photos to existing requests
CREATE POLICY "Staff can upload maintenance photos"
ON storage.objects FOR INSERT TO authenticated
WITH CHECK (bucket_id = 'maintenance-photos');


-- >>>>> migrations/008_maintenance_photos_rls.sql >>>>>
-- ============================================================================
-- Migration 008: Tighten RLS for maintenance-photos storage bucket
-- ============================================================================
-- Replaces the permissive INSERT policy from migration 007 (which allowed any
-- authenticated user to upload to any path in the bucket) with a policy that
-- binds uploads to either the 'temp/' staging folder or an existing maintenance
-- request UUID. Also adds UPDATE/DELETE policies for privileged roles so
-- orphan photos can actually be cleaned up.
-- ============================================================================

-- 1. Drop the permissive INSERT policy from 007
DROP POLICY IF EXISTS "Staff can upload maintenance photos" ON storage.objects;

-- 2. Allow INSERT only when the path prefix is either 'temp' or an existing request UUID
CREATE POLICY "Staff can upload maintenance photos (bound to request)"
ON storage.objects FOR INSERT TO authenticated
WITH CHECK (
  bucket_id = 'maintenance-photos'
  AND (
    split_part(name, '/', 1) = 'temp'
    OR EXISTS (
      SELECT 1 FROM public.maintenance_requests
      WHERE id::text = split_part(name, '/', 1)
    )
  )
);

-- 3. Allow DELETE only to privileged roles (cleanup, reorganisation)
CREATE POLICY "Privileged staff can delete maintenance photos"
ON storage.objects FOR DELETE TO authenticated
USING (
  bucket_id = 'maintenance-photos'
  AND EXISTS (
    SELECT 1 FROM public.staff_profiles
    WHERE id = auth.uid()
      AND is_active
      AND role IN ('super_admin', 'branch_manager', 'maintenance_staff')
  )
);

-- 4. Allow UPDATE only to privileged roles (rename/move)
CREATE POLICY "Privileged staff can update maintenance photos"
ON storage.objects FOR UPDATE TO authenticated
USING (
  bucket_id = 'maintenance-photos'
  AND EXISTS (
    SELECT 1 FROM public.staff_profiles
    WHERE id = auth.uid()
      AND is_active
      AND role IN ('super_admin', 'branch_manager', 'maintenance_staff')
  )
);


-- >>>>> migrations/009_maintenance_summary_refactor.sql >>>>>
-- ============================================================================
-- Migration 009: Maintenance Summary Refactor
-- ============================================================================
-- Retires `title` as a required field on maintenance_requests. The short
-- description becomes the primary summary (≤150 chars, enforced at the
-- application layer), and a new `extra_details` column captures long-form
-- text when the summary isn't enough.
--
-- The `title` column is kept (made nullable) to preserve historical data and
-- allow easy rollback. A one-time backfill copies title into description for
-- any legacy row whose description is empty, so the admin Summary column
-- isn't blank for existing records.
-- ============================================================================

ALTER TABLE maintenance_requests
  ALTER COLUMN title DROP NOT NULL;

ALTER TABLE maintenance_requests
  ADD COLUMN IF NOT EXISTS extra_details TEXT;

UPDATE maintenance_requests
SET description = LEFT(title, 150)
WHERE (description IS NULL OR description = '')
  AND title IS NOT NULL
  AND title <> '';


-- >>>>> migrations/010_protect_last_super_admin.sql >>>>>
-- ============================================================================
-- Protect against losing the last active super_admin under concurrent writes.
--
-- The user-management API previously enforced this with an application-level
-- count + update, which is racy: two concurrent demotions of two different
-- active super_admins both pass the count check and both succeed, leaving
-- zero active super_admins. We move the guard into the database:
--
--   1. A trigger BEFORE UPDATE on staff_profiles aborts any update that
--      would leave the count of (role='super_admin' AND is_active=true)
--      at zero. The trigger uses an advisory lock to serialize concurrent
--      updates that touch the super_admin pool, eliminating the TOCTOU race.
--   2. An SECURITY DEFINER RPC `update_staff_profile_safely` that the API
--      can call to perform updates atomically and surface a friendly error
--      code (`last_super_admin`) instead of a raw SQL exception string.
-- ============================================================================

-- Stable lock id derived from a salted hash of "staff_profiles:super_admin_pool".
-- pg_advisory_xact_lock takes a bigint; any deterministic id works.
CREATE OR REPLACE FUNCTION public._super_admin_lock()
RETURNS void AS $$
  SELECT pg_advisory_xact_lock(8675309001::bigint);
$$ LANGUAGE sql;

CREATE OR REPLACE FUNCTION public.protect_last_super_admin()
RETURNS trigger AS $$
DECLARE
  remaining_count integer;
BEGIN
  -- Only relevant if this update could remove an active super_admin.
  IF OLD.role = 'super_admin' AND OLD.is_active = true
     AND (NEW.role <> 'super_admin' OR NEW.is_active = false) THEN

    -- Serialize all updates that affect the super_admin pool inside the
    -- transaction. Concurrent updates wait here.
    PERFORM public._super_admin_lock();

    SELECT count(*) INTO remaining_count
    FROM public.staff_profiles
    WHERE role = 'super_admin'
      AND is_active = true
      AND id <> OLD.id;

    IF remaining_count = 0 THEN
      RAISE EXCEPTION 'last_super_admin'
        USING ERRCODE = 'check_violation';
    END IF;
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_protect_last_super_admin ON public.staff_profiles;
CREATE TRIGGER trg_protect_last_super_admin
  BEFORE UPDATE OF role, is_active ON public.staff_profiles
  FOR EACH ROW
  EXECUTE FUNCTION public.protect_last_super_admin();

-- Same protection for hard deletes (in case anyone bypasses the API and
-- runs a raw DELETE — the API itself returns 405, but defense in depth).
CREATE OR REPLACE FUNCTION public.protect_last_super_admin_on_delete()
RETURNS trigger AS $$
DECLARE
  remaining_count integer;
BEGIN
  IF OLD.role = 'super_admin' AND OLD.is_active = true THEN
    PERFORM public._super_admin_lock();

    SELECT count(*) INTO remaining_count
    FROM public.staff_profiles
    WHERE role = 'super_admin'
      AND is_active = true
      AND id <> OLD.id;

    IF remaining_count = 0 THEN
      RAISE EXCEPTION 'last_super_admin'
        USING ERRCODE = 'check_violation';
    END IF;
  END IF;

  RETURN OLD;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_protect_last_super_admin_delete ON public.staff_profiles;
CREATE TRIGGER trg_protect_last_super_admin_delete
  BEFORE DELETE ON public.staff_profiles
  FOR EACH ROW
  EXECUTE FUNCTION public.protect_last_super_admin_on_delete();


-- >>>>> migrations/011_role_expansion_enum.sql >>>>>
-- ============================================================================
-- Migration 011: Role expansion — add 4 new values to user_role enum
-- ============================================================================
-- Adds department-manager tier and a deputy-GM role above branch_manager.
--   - maintenance_manager       (peer of maintenance_staff, manager tier)
--   - transportation_manager    (peer of transportation_staff, manager tier)
--   - finance_manager           (peer of finance_staff, manager tier)
--   - deputy_general_manager    (super_admin-equivalent, except user mgmt)
--
-- Postgres allows ADD VALUE inside a transaction, but the new values cannot
-- be referenced in the SAME transaction. RLS policy updates that reference
-- these values therefore live in migration 012.
-- ============================================================================

ALTER TYPE user_role ADD VALUE IF NOT EXISTS 'maintenance_manager';
ALTER TYPE user_role ADD VALUE IF NOT EXISTS 'transportation_manager';
ALTER TYPE user_role ADD VALUE IF NOT EXISTS 'finance_manager';
ALTER TYPE user_role ADD VALUE IF NOT EXISTS 'deputy_general_manager';


-- >>>>> migrations/012_role_expansion_rls.sql >>>>>
-- ============================================================================
-- Migration 012: Role expansion — RLS updates for new roles
-- ============================================================================
-- Mirrors the access of department-manager roles to their staff counterpart,
-- and grants deputy_general_manager super_admin-equivalent access to every
-- table EXCEPT staff_profiles (user management remains super_admin only).
--
-- Strategy:
--   1. New helper has_admin_access() = role IN ('super_admin','deputy_general_manager')
--   2. Replace each existing `*_admin_all` policy that was using is_super_admin()
--      with one that uses has_admin_access(), EXCEPT for staff_profiles policies.
--   3. Extend role-list policies (e.g. bookings_staff_select) to include the
--      manager peer of each staff role they reference.
-- ============================================================================

-- ----------------------------------------------------------------------------
-- 1. Helper: has_admin_access() — super_admin OR deputy_general_manager
-- ----------------------------------------------------------------------------

CREATE OR REPLACE FUNCTION public.has_admin_access()
RETURNS BOOLEAN AS $$
  SELECT EXISTS (
    SELECT 1 FROM public.staff_profiles
    WHERE id = auth.uid()
      AND role IN ('super_admin', 'deputy_general_manager')
      AND is_active = true
  );
$$ LANGUAGE sql SECURITY DEFINER STABLE;

-- ----------------------------------------------------------------------------
-- 2. Replace `*_admin_all` policies on non-staff-profile tables
--    (staff_profiles user-management policies stay restricted to super_admin)
-- ----------------------------------------------------------------------------

